  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// Build 44 board positions
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Modal Styles ---
const modalStyles = {
  overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 },
  modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" },
  button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" },
};


// --- Modal Components ---
const CardModal = ({ property, onClose, onBuy }) => {
  if (!property) return null;
  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h3>{property.name}</h3>
        <p>Price: ${property.price}</p>
        <p>Rent: Base ${property.rent.base}</p>
        <button style={modalStyles.button} onClick={() => { onBuy(property); onClose(); }}>
          Buy
        </button>
        <button style={modalStyles.button} onClick={onClose}>Close</button>
      </div>
    </div>
  );
};

const AssetsModal = ({ player, onClose }) => {
  if (!player) return null;
  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h3>{player.name}'s Properties</h3>
        {player.properties.length === 0 ? <p>No properties owned</p> :
          <ul>
            {player.properties.map((prop, idx) => (
              <li key={idx}>{prop.name} - Rent ${prop.rent.base}</li>
            ))}
          </ul>
        }
        <p>Cash: ${player.cash}</p>
        <button style={modalStyles.button} onClick={onClose}>Close</button>
      </div>
    </div>
  );
};

// --- Main App ---
function App() {
  const [players, setPlayers] = useState([
    { name: "Player 1", position: 0, cash: 1500, properties: [] },
    { name: "Player 2", position: 0, cash: 1500, properties: [] },
  ]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [diceRoll, setDiceRoll] = useState(null);
  const [showCard, setShowCard] = useState(null);
  const [showAssets, setShowAssets] = useState(null);

  const currentPlayer = players[currentPlayerIndex];

  const rollDice = (value) => {
    const newPos = (currentPlayer.position + value) % 44;
    const newPlayers = [...players];
    newPlayers[currentPlayerIndex] = { ...currentPlayer, position: newPos };
    setPlayers(newPlayers);

    // Check for property at new position
    const event = boardEvents[newPos];
    if (event && event.type === "property") {
      setShowCard(event.card);
    } else {
      setShowCard(null);
    }

    // Next player's turn
    setCurrentPlayerIndex((currentPlayerIndex + 1) % players.length);
  };

  const buyProperty = (property) => {
    if (currentPlayer.cash >= property.price) {
      const newPlayers = [...players];
      newPlayers[currentPlayerIndex] = {
        ...currentPlayer,
        cash: currentPlayer.cash - property.price,
        properties: [...currentPlayer.properties, property],
      };
      setPlayers(newPlayers);

      // Assign owner
      property.ownerIndex = currentPlayerIndex;
    } else {
      alert("Not enough cash to buy this property.");
    }
  };

  const payRent = (ownerIndex, amount) => {
    if (ownerIndex === null) return;
    const newPlayers = [...players];
    if (currentPlayer.cash >= amount) {
      newPlayers[currentPlayerIndex].cash -= amount;
      newPlayers[ownerIndex].cash += amount;
    } else {
      alert(`${currentPlayer.name} cannot pay full rent!`);
      // Optional: handle bankruptcy
    }
    setPlayers(newPlayers);
  };

  // Auto check rent if player lands on owned property
  useEffect(() => {
    const player = players[currentPlayerIndex];
    const event = boardEvents[player.position];
    if (event && event.type === "property" && event.card.ownerIndex !== null && event.card.ownerIndex !== currentPlayerIndex) {
      payRent(event.card.ownerIndex, event.card.rent.base);
    }
    // eslint-disable-next-line
  }, [players]);

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", padding: 20 }}>
      <h2>TorahPoly</h2>
      <div style={{ position: "relative", width: referenceSize, height: referenceSize }}>
        <img src={boardImage} alt="Board" style={{ width: "100%", height: "100%" }} />
        {players.map((p, idx) => {
          const pos = defaultBoardPositions[p.position];
          return (
            <div key={idx} style={{
              position: "absolute",
              width: 25, height: 25, borderRadius: "50%",
              backgroundColor: idx === 0 ? "red" : "blue",
              left: pos.x - 12, top: pos.y - 12,
            }} />
          );
        })}
      </div>

      <div style={{ marginTop: 20 }}>
        <Dice size={80} onRoll={(value) => rollDice(value)} />
        <p>Current Player: {currentPlayer.name}</p>
        <p>Cash: ${currentPlayer.cash}</p>
        <button style={modalStyles.button} onClick={() => setShowAssets(currentPlayer)}>My Properties</button>
      </div>

      {showCard && <CardModal property={showCard} onClose={() => setShowCard(null)} onBuy={buyProperty} />}
      {showAssets && <AssetsModal player={showAssets} onClose={() => setShowAssets(null)} />}
    </div>
  );
}

export default App;
